import fs from 'fs';
const pdfParse = require('pdf-parse');

async function testPdfParse() {
    try {
        console.log('Starting pdf-parse test...');

        // Let's create a minimal valid PDF base64 for testing
        // This is a minimal valid PDF containing "Hello World"
        const minimalPdfBase64 = "";

        const buffer = Buffer.from(minimalPdfBase64, 'base64');
        console.log(`Buffer created, size: ${buffer.length} bytes`);

        const pdfData = await pdfParse(buffer);
        console.log('Success! Extracted text:', pdfData.text);
    } catch (err: any) {
        console.error('Test Failed! Error:', err.message);
        console.error(err);
    }
}

testPdfParse();
